def HSS(points, k: int, reference_point) -> np.ndarray:
    import numpy as np
    import heapq

    try:
        import pygmo as pg
    except Exception:
        raise ImportError("pygmo is required for hypervolume computations (pip install pygmo).")

    points = np.asarray(points, dtype=float)
    if points.ndim != 2:
        raise ValueError("points must be a 2D array of shape (N, D)")
    n, m = points.shape

    if k <= 0:
        return np.zeros((0, m))
    if k >= n:
        return points.copy()

    # Reference point handling
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float)
    if reference_point.shape != (m,):
        raise ValueError("reference_point must have shape (D,) matching points' dimension")
    max_pts = np.max(points, axis=0)
    reference_point = np.maximum(reference_point, max_pts * 1.0 + 1e-8)

    # Filter out dominated points (Pareto pruning)
    pts = points.copy()
    n2 = pts.shape[0]
    dominated = np.zeros(n2, dtype=bool)
    for i in range(n2):
        if dominated[i]:
            continue
        ge = np.all(pts >= pts[i], axis=1)
        gt = np.any(pts > pts[i], axis=1)
        dom_by = np.where(ge & gt)[0]
        for j in dom_by:
            if j != i:
                dominated[i] = True
                break
    keep_idx = np.where(~dominated)[0]
    if keep_idx.size == 0:
        # fallback, return k arbitrary points
        return points[:min(k, n), :].copy()

    points_f = pts[keep_idx, :]
    orig_idx_map = keep_idx
    n_f = points_f.shape[0]

    # If we have fewer non-dominated points than k, include all and pad later
    if n_f == 0:
        return points[:min(k, n), :].copy()
    if k >= n_f:
        # will pad with dominated originals later
        selected_all = points_f.copy()
        if selected_all.shape[0] >= k:
            return selected_all[:k, :].copy()

    # Precompute single-point hypervolumes (upper bounds)
    single_hvs = np.empty(n_f, dtype=float)
    for i in range(n_f):
        try:
            single_hvs[i] = pg.hypervolume(points_f[i:i+1, :]).compute(reference_point)
        except Exception:
            single_hvs[i] = 0.0

    # Lazy greedy using a max-heap of estimated gains (initially single_hvs)
    selected_mask = np.zeros(n_f, dtype=bool)
    selected_idx = []
    selected_points = np.empty((0, m), dtype=float)
    current_hv = 0.0
    tol = 1e-12

    # Build heap: (-est_gain, idx, est_gain)
    heap = [(-single_hvs[i], i, single_hvs[i]) for i in range(n_f)]
    heapq.heapify(heap)

    selections = 0
    while selections < min(k, n_f) and heap:
        neg_est, idx, est = heapq.heappop(heap)
        if selected_mask[idx]:
            continue  # already selected
        # Recompute true marginal gain for idx
        cand = points_f[idx:idx+1, :]
        try:
            if selected_points.size == 0:
                hv_combined = pg.hypervolume(cand).compute(reference_point)
            else:
                hv_combined = pg.hypervolume(np.vstack([selected_points, cand])).compute(reference_point)
        except Exception:
            hv_combined = 0.0
        true_gain = hv_combined - current_hv
        # If the estimate was optimistic and true_gain is significantly smaller, push updated value
        if true_gain < est - tol:
            # push updated estimate back
            heapq.heappush(heap, (-true_gain, idx, true_gain))
            continue
        # Otherwise accept this candidate
        selected_mask[idx] = True
        selected_idx.append(idx)
        if selected_points.size == 0:
            selected_points = cand.copy()
        else:
            selected_points = np.vstack([selected_points, cand])
        try:
            current_hv = pg.hypervolume(selected_points).compute(reference_point)
        except Exception:
            current_hv = 0.0
        selections += 1

    # If we didn't select enough due to numerical issues, fill by highest single_hvs remaining
    if len(selected_idx) < min(k, n_f):
        remaining = np.where(~selected_mask)[0]
        order = remaining[np.argsort(-single_hvs[remaining])]
        for idx in order:
            if len(selected_idx) >= min(k, n_f):
                break
            selected_mask[idx] = True
            selected_idx.append(idx)
            cand = points_f[idx:idx+1, :]
            if selected_points.size == 0:
                selected_points = cand.copy()
            else:
                selected_points = np.vstack([selected_points, cand])
            try:
                current_hv = pg.hypervolume(selected_points).compute(reference_point)
            except Exception:
                current_hv = 0.0

    # Local 1-for-1 swap improvement (try to escape local opt)
    max_swap_iters = 5
    improved = True
    swap_iter = 0
    while improved and swap_iter < max_swap_iters:
        improved = False
        swap_iter += 1
        # For each selected position, try replacements
        for pos_in_sel, sel_f_idx in enumerate(list(selected_idx)):
            remaining = np.where(~selected_mask)[0]
            if remaining.size == 0:
                break
            # try candidates ordered by single_hvs descending
            cand_order = remaining[np.argsort(-single_hvs[remaining])]
            for cand_f_idx in cand_order:
                # propose swap
                trial = selected_points.copy()
                trial[pos_in_sel, :] = points_f[cand_f_idx, :]
                try:
                    hv_trial = pg.hypervolume(trial).compute(reference_point)
                except Exception:
                    hv_trial = 0.0
                if hv_trial > current_hv + tol:
                    # accept swap
                    selected_mask[sel_f_idx] = False
                    selected_mask[cand_f_idx] = True
                    selected_idx[pos_in_sel] = cand_f_idx
                    selected_points = trial
                    current_hv = hv_trial
                    improved = True
                    break
            if improved:
                break

    # Map selected indices back to original points
    final_filtered_indices = np.array(selected_idx, dtype=int)
    final_original_indices = orig_idx_map[final_filtered_indices]
    subset = points[final_original_indices, :].copy()

    # If fewer than k due to filtering, pad by taking from dominated originals first, ranked by single-point hv if possible
    if subset.shape[0] < k:
        needed = k - subset.shape[0]
        remaining_orig = np.setdiff1d(np.arange(n), final_original_indices, assume_unique=True)
        if remaining_orig.size > 0:
            # Try to prefer non-dominated remaining by using mapping if available
            # compute simple scores for remaining (single point hv if in filtered set, else approximate by point volume)
            scores = []
            for idx in remaining_orig:
                if idx in orig_idx_map:
                    # this shouldn't normally happen, but keep safe
                    fid = np.where(orig_idx_map == idx)[0]
                    sc = single_hvs[fid[0]] if fid.size else 0.0
                else:
                    # approximate by box volume (reference - point) product as cheap proxy
                    diff = reference_point - points[idx]
                    diff = np.maximum(diff, 0.0)
                    sc = np.prod(diff)
                scores.append(sc)
            scores = np.array(scores)
            order = np.argsort(-scores)
            take = remaining_orig[order][:needed]
            extra = points[take, :]
            subset = np.vstack([subset, extra])

    # Ensure shape (k, m)
    if subset.shape[0] > k:
        subset = subset[:k, :]
    return subset[:k, :].copy()

def HSS(points, k: int, reference_point) -> np.ndarray:
    import numpy as np
    try:
        import pygmo as pg
    except Exception:
        pg = None

    points = np.asarray(points, dtype=float)
    if points.ndim != 2:
        raise ValueError("points must be a 2D array of shape (N, D)")
    n, d = points.shape

    # trivial cases
    if k <= 0:
        return np.zeros((0, d), dtype=float)
    if k >= n:
        return points.copy()

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float)
    if reference_point.shape != (d,):
        raise ValueError("reference_point must have shape (D,) matching points' dimension")

    # hypervolume computation helper
    def hv_of_indices(idx_list):
        if len(idx_list) == 0:
            return 0.0
        arr = points[np.array(idx_list, dtype=int)]
        if pg is not None:
            try:
                # pygmo expects objectives in minimization sense for hypervolume compute,
                # but when computing hypervolume against a reference point, passing points and reference should work.
                return float(pg.hypervolume(arr).compute(reference_point))
            except Exception:
                # fallback to approximate below
                pass
        # crude fallback when pygmo not available or failed:
        # approximate union by summing single box volumes and subtracting pairwise overlaps (very rough)
        diffs = np.maximum(reference_point - arr, 0.0)
        try:
            if arr.shape[0] == 1:
                return float(np.prod(diffs[0]))
            single = np.prod(diffs, axis=1)
            approx = float(single.sum())
            # subtract pairwise min-volumes scaled to partially account for overlap
            m = arr.shape[0]
            if m > 1:
                # efficient pairwise loop but bounded if too many points
                max_pairs = 200000  # avoid extreme cost
                est_pairs = m * (m - 1) // 2
                if est_pairs > max_pairs:
                    # sample some pairs
                    rng = np.random.default_rng(0)
                    pairs_to_sample = max_pairs
                    for _ in range(pairs_to_sample):
                        i = int(rng.integers(0, m))
                        j = int(rng.integers(0, m - 1))
                        if j >= i:
                            j += 1
                        mins = np.minimum(diffs[i], diffs[j])
                        approx -= 0.5 * float(np.prod(mins))
                else:
                    for i in range(m):
                        for j in range(i + 1, m):
                            mins = np.minimum(diffs[i], diffs[j])
                            approx -= 0.5 * float(np.prod(mins))
            return max(0.0, approx)
        except Exception:
            return 0.0

    # Precompute single-point hypervolumes (upper bounds)
    single_hvs = np.zeros(n, dtype=float)
    for i in range(n):
        single_hvs[i] = hv_of_indices([i])

    # Sort indices by descending single_hv (candidates with larger potential first)
    sorted_idx = list(np.argsort(-single_hvs))

    selected_indices = []
    selected_set = set()
    current_hv = 0.0
    tol = 1e-12

    # batch size strategy: adapt to problem size for performance
    batch_base = max(10, min(100, k * 3))
    # ensure at least 1 and at most n
    batch_base = int(min(max(1, batch_base), n))

    # Main loop: at each iteration evaluate exact marginal hv on top-B unselected candidates
    while len(selected_indices) < k:
        # build pool of top-B unselected candidates from sorted list
        pool = []
        for idx in sorted_idx:
            if idx in selected_set:
                continue
            pool.append(idx)
            if len(pool) >= batch_base:
                break
        if len(pool) == 0:
            break  # no more candidates

        # compute exact marginal gains for pool
        best_idx = None
        best_delta = -np.inf
        for idx in pool:
            delta = hv_of_indices(selected_indices + [idx]) - current_hv
            if delta < 0:
                delta = 0.0
            if delta > best_delta + tol:
                best_delta = delta
                best_idx = idx

        # If best marginal is tiny (near zero), stop greedy; we'll fill remaining slots by single_hvs
        if best_delta <= tol or best_idx is None:
            break

        # select best
        selected_indices.append(int(best_idx))
        selected_set.add(int(best_idx))
        current_hv = hv_of_indices(selected_indices)  # update exactly

        # optionally increase batch if selection isn't making progress? keep static for simplicity

    # Fill remaining slots by highest single_hv unselected points
    if len(selected_indices) < k:
        for idx in sorted_idx:
            if idx in selected_set:
                continue
            selected_indices.append(int(idx))
            selected_set.add(int(idx))
            if len(selected_indices) >= k:
                break
        current_hv = hv_of_indices(selected_indices)

    subset = points[np.array(selected_indices[:k], dtype=int), :]
    return subset

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    import numpy as np
    import heapq

    try:
        import pygmo as pg
    except Exception:
        pg = None

    points = np.asarray(points, dtype=float)
    if points.ndim != 2:
        raise ValueError("points must be a 2D array of shape (N, D)")
    n, d = points.shape

    # trivial cases
    if k <= 0:
        return np.zeros((0, d), dtype=float)
    if k >= n:
        return points.copy()

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float)
    if reference_point.shape != (d,):
        raise ValueError("reference_point must have shape (D,) matching points' dimension")

    # hypervolume computation helper (exact via pygmo if available, otherwise fallback approx)
    def hv_of_indices(idx_list):
        if len(idx_list) == 0:
            return 0.0
        arr = points[np.array(idx_list, dtype=int)]
        if pg is not None:
            try:
                # pygmo hypervolume expects a 2D array of points (objectives), compute() takes reference
                return float(pg.hypervolume(arr).compute(reference_point))
            except Exception:
                pass
        # fallback approximate union-of-boxes (fast but not exact)
        diffs = np.maximum(reference_point - arr, 0.0)
        try:
            if arr.shape[0] == 1:
                return float(np.prod(diffs[0]))
            single = np.prod(diffs, axis=1)
            approx = float(single.sum())
            m = arr.shape[0]
            if m > 1:
                max_pairs = 200000
                est_pairs = m * (m - 1) // 2
                if est_pairs > max_pairs:
                    rng = np.random.default_rng(0)
                    for _ in range(max_pairs):
                        i = int(rng.integers(0, m))
                        j = int(rng.integers(0, m - 1))
                        if j >= i:
                            j += 1
                        mins = np.minimum(diffs[i], diffs[j])
                        approx -= 0.5 * float(np.prod(mins))
                else:
                    for i in range(m):
                        for j in range(i + 1, m):
                            mins = np.minimum(diffs[i], diffs[j])
                            approx -= 0.5 * float(np.prod(mins))
            return max(0.0, approx)
        except Exception:
            return 0.0

    # Precompute single-point hypervolumes (upper bounds / initial marginal estimates)
    single_hvs = np.zeros(n, dtype=float)
    for i in range(n):
        single_hvs[i] = hv_of_indices([i])

    # Build max-heap of candidates with initial marginal = single_hv
    # Heap entries: (-marginal, idx, last_selected_count) where last_selected_count indicates
    # the selection size when marginal was computed
    heap = []
    for i in range(n):
        # last_selected_count = 0 (no points selected yet)
        heap.append((-single_hvs[i], int(i), 0))
    heapq.heapify(heap)

    selected_indices = []
    selected_set = set()
    current_hv = 0.0
    tol = 1e-12
    selected_count = 0

    # Lazy greedy (CELF-like): pop top, if its stored marginal was computed for current selected_count,
    # accept it; otherwise recompute actual marginal and push back with updated timestamp.
    while selected_count < k and heap:
        neg_marginal, idx, last_count = heapq.heappop(heap)
        if idx in selected_set:
            continue  # already selected via some path (shouldn't normally happen)
        stored_marginal = -neg_marginal
        if last_count == selected_count:
            # marginal valid -> select if positive
            if stored_marginal <= tol:
                break  # no useful improvement remains
            selected_indices.append(int(idx))
            selected_set.add(int(idx))
            selected_count += 1
            current_hv = hv_of_indices(selected_indices)  # exact update
            # continue selecting next
        else:
            # need to recompute true marginal w.r.t current selection
            new_hv = hv_of_indices(selected_indices + [int(idx)])
            new_marginal = max(0.0, new_hv - current_hv)
            # push back with updated timestamp
            heapq.heappush(heap, (-new_marginal, int(idx), selected_count))

    # If we stopped early (no positive marginals) or heap exhausted, fill remaining by top single_hvs
    if len(selected_indices) < k:
        # sort indices by single_hvs descending and pick unselected
        order = np.argsort(-single_hvs)
        for idx in order:
            if idx in selected_set:
                continue
            selected_indices.append(int(idx))
            selected_set.add(int(idx))
            if len(selected_indices) >= k:
                break
        # update current hv (best effort)
        current_hv = hv_of_indices(selected_indices)

    subset = points[np.array(selected_indices[:k], dtype=int), :].astype(float, copy=True)
    return subset
